using System;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    /// <summary>
    /// AOT-compatible converter for <see cref="ResponseError"/> since the built-in
    /// converter in Azure.Core is not publicly accessible for source generation.
    /// </summary>
    internal class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var document = JsonDocument.ParseValue(ref reader);
            var root = document.RootElement;
            string code = null;
            string message = null;
            if (root.TryGetProperty("code", out var codeProp))
            {
                code = codeProp.GetString();
            }
            if (root.TryGetProperty("message", out var msgProp))
            {
                message = msgProp.GetString();
            }
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code", value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message", value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

